module RefModule (
	input clk,
	input rst,
	input dir,
	output reg [8:0] count);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (rst)
		count <= 9'b000000000;
	else if (dir)
		count <= count + 1;
	else
		count <= count - 1;
end

endmodule
